// Annotation Manager - Handles all annotation operations
export class AnnotationManager {
  constructor(fileName) {
    this.fileName = fileName;
    this.viewer = null;
    this.annotations = [];
    this.currentTool = 'select';
    this.currentColor = '#e0af68'; // Default yellow for highlights
    this.currentOpacity = 0.4;
    this.currentSize = 2;
    this.annotationIdCounter = 0;
    
    // FIX: Do NOT call setupDrawingCallbacks() here — viewer is null at construction time.
    // Callbacks are attached in setViewer() instead.
  }

  setViewer(viewer) {
    this.viewer = viewer;
    // FIX: Set up callbacks NOW that we have a viewer reference
    this.setupDrawingCallbacks();
  }

  setupDrawingCallbacks() {
    if (!this.viewer) return;
    
    this.viewer.onDrawingEnd = (path, startPos, endPos) => {
      this.createAnnotationFromPath(path, startPos, endPos);
    };
    
    this.viewer.onTextAnnotationClick = (e) => {
      this.createTextAnnotation(e);
    };
  }

  setTool(tool) {
    this.currentTool = tool;
  }

  setColor(color) {
    this.currentColor = color;
  }

  setOpacity(opacity) {
    this.currentOpacity = opacity;
  }

  setSize(size) {
    this.currentSize = size;
  }

  async createAnnotationFromPath(path, startPos, endPos) {
    if (!this.viewer || path.length < 2) return;
    
    const pageInfo = this.viewer.getPageFromPosition(startPos);
    if (!pageInfo) return;
    
    // FIX: Correctly resolve local coordinates relative to the page container
    const pageTop = pageInfo.page.pageContainer.offsetTop;
    const annotation = {
      id: this.generateId(),
      type: this.currentTool,
      page: pageInfo.page.pageNum,
      path: path.map(p => ({ x: p.x, y: p.y - pageTop })),
      startPos: { x: startPos.x, y: startPos.y - pageTop },
      endPos:   { x: endPos.x,   y: endPos.y - pageTop },
      color: this.currentColor,
      opacity: this.currentOpacity,
      size: this.currentSize,
      createdAt: Date.now()
    };
    
    this.annotations.push(annotation);
    this.renderAnnotation(annotation);
    this.onAnnotationsChanged?.(this.annotations);
    // FIX: Auto-save after each annotation
    await this.saveToStorage();
  }

  async createTextAnnotation(e) {
    if (!this.viewer) return;
    
    const rect = this.viewer.container.getBoundingClientRect();
    const absX = e.clientX - rect.left + this.viewer.container.scrollLeft;
    const absY = e.clientY - rect.top  + this.viewer.container.scrollTop;
    
    const pos = { x: absX, y: absY };
    const pageInfo = this.viewer.getPageFromPosition(pos);
    if (!pageInfo) return;
    
    const pageTop = pageInfo.page.pageContainer.offsetTop;
    const annotation = {
      id: this.generateId(),
      type: 'text',
      page: pageInfo.page.pageNum,
      // FIX: Store page-relative coordinates
      position: { x: absX, y: absY - pageTop },
      color: this.currentColor,
      text: '',
      createdAt: Date.now()
    };
    
    this.annotations.push(annotation);
    this.renderTextAnnotation(annotation);
    this.onAnnotationsChanged?.(this.annotations);
    
    setTimeout(() => {
      const textarea = document.querySelector(`[data-annotation-id="${annotation.id}"] textarea`);
      if (textarea) textarea.focus();
    }, 100);
  }

  generateId() {
    return `annotation_${++this.annotationIdCounter}_${Date.now()}`;
  }

  renderAnnotation(annotation) {
    const annotationLayer = this.viewer.getAnnotationLayer(annotation.page);
    if (!annotationLayer) return;
    
    const el = document.createElement('div');
    el.className = `annotation-${annotation.type}`;
    el.dataset.annotationId = annotation.id;
    // FIX: All annotation elements must be absolutely positioned within the layer
    el.style.position = 'absolute';
    
    switch (annotation.type) {
      case 'highlight':
        this.renderHighlight(el, annotation);
        break;
      case 'underline':
        this.renderUnderline(el, annotation);
        break;
      case 'strikethrough':
        this.renderStrikethrough(el, annotation);
        break;
      case 'draw':
        this.renderDrawing(el, annotation);
        break;
    }
    
    annotationLayer.appendChild(el);
  }

  renderHighlight(el, annotation) {
    const startX = Math.min(annotation.startPos.x, annotation.endPos.x);
    const startY = Math.min(annotation.startPos.y, annotation.endPos.y);
    const width  = Math.abs(annotation.endPos.x - annotation.startPos.x);
    const height = Math.abs(annotation.endPos.y - annotation.startPos.y);
    
    el.style.left            = startX + 'px';
    el.style.top             = startY + 'px';
    el.style.width           = width  + 'px';
    el.style.height          = height + 'px';
    el.style.backgroundColor = annotation.color;
    el.style.opacity         = annotation.opacity;
    el.style.pointerEvents   = 'none';
    el.title = `Highlight - Page ${annotation.page}`;
  }

  renderUnderline(el, annotation) {
    const dx = annotation.endPos.x - annotation.startPos.x;
    const dy = annotation.endPos.y - annotation.startPos.y;
    const length = Math.sqrt(dx * dx + dy * dy);
    const angle  = Math.atan2(dy, dx) * 180 / Math.PI;
    
    el.style.left            = annotation.startPos.x + 'px';
    el.style.top             = annotation.startPos.y + 'px';
    el.style.width           = length + 'px';
    el.style.height          = annotation.size + 'px';
    el.style.backgroundColor = annotation.color;
    el.style.opacity         = annotation.opacity;
    el.style.transformOrigin = '0 50%';
    el.style.transform       = `rotate(${angle}deg)`;
    el.style.pointerEvents   = 'none';
    el.title = `Underline - Page ${annotation.page}`;
  }

  renderStrikethrough(el, annotation) {
    const dx = annotation.endPos.x - annotation.startPos.x;
    const dy = annotation.endPos.y - annotation.startPos.y;
    const length = Math.sqrt(dx * dx + dy * dy);
    const angle  = Math.atan2(dy, dx) * 180 / Math.PI;
    
    el.style.left            = annotation.startPos.x + 'px';
    // FIX: offset upward by half the text height (approx 8px) for strikethrough effect
    el.style.top             = (annotation.startPos.y - 8) + 'px';
    el.style.width           = length + 'px';
    el.style.height          = annotation.size + 'px';
    el.style.backgroundColor = annotation.color;
    el.style.opacity         = annotation.opacity;
    el.style.transformOrigin = '0 50%';
    el.style.transform       = `rotate(${angle}deg)`;
    el.style.pointerEvents   = 'none';
    el.title = `Strikethrough - Page ${annotation.page}`;
  }

  renderDrawing(el, annotation) {
    if (annotation.path.length < 2) return;
    
    // FIX: Size the SVG to the bounding box of the path, not 100%/100%
    // which causes clicks to be blocked over the whole page
    const xs = annotation.path.map(p => p.x);
    const ys = annotation.path.map(p => p.y);
    const minX = Math.min(...xs) - annotation.size;
    const minY = Math.min(...ys) - annotation.size;
    const maxX = Math.max(...xs) + annotation.size;
    const maxY = Math.max(...ys) + annotation.size;
    const w = maxX - minX;
    const h = maxY - minY;
    
    el.style.left   = minX + 'px';
    el.style.top    = minY + 'px';
    el.style.width  = w + 'px';
    el.style.height = h + 'px';
    
    const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.setAttribute('width',   w);
    svg.setAttribute('height',  h);
    svg.setAttribute('viewBox', `${minX} ${minY} ${w} ${h}`);
    svg.style.position      = 'absolute';
    svg.style.left          = '0';
    svg.style.top           = '0';
    svg.style.pointerEvents = 'none';
    
    const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    
    let pathD = `M ${annotation.path[0].x} ${annotation.path[0].y}`;
    for (let i = 1; i < annotation.path.length; i++) {
      pathD += ` L ${annotation.path[i].x} ${annotation.path[i].y}`;
    }
    
    path.setAttribute('d',                pathD);
    path.setAttribute('stroke',           annotation.color);
    path.setAttribute('stroke-width',     annotation.size);
    path.setAttribute('fill',             'none');
    path.setAttribute('stroke-linecap',   'round');
    path.setAttribute('stroke-linejoin',  'round');
    path.setAttribute('opacity',          annotation.opacity);
    
    svg.appendChild(path);
    el.appendChild(svg);
    el.title = `Drawing - Page ${annotation.page}`;
  }

  renderTextAnnotation(annotation) {
    const annotationLayer = this.viewer.getAnnotationLayer(annotation.page);
    if (!annotationLayer) return;
    
    const el = document.createElement('div');
    el.className = 'annotation-text-note';
    el.dataset.annotationId = annotation.id;
    // FIX: position must be set (layer is relative, el is absolute)
    el.style.position = 'absolute';
    el.style.left     = annotation.position.x + 'px';
    el.style.top      = annotation.position.y + 'px';
    
    el.innerHTML = `
      <div class="note-header">
        <div class="note-color" style="background: ${annotation.color}"></div>
        <button class="note-delete" data-annotation-id="${annotation.id}">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
            <line x1="18" y1="6" x2="6" y2="18"/>
            <line x1="6" y1="6" x2="18" y2="18"/>
          </svg>
        </button>
      </div>
      <textarea placeholder="Type your note...">${annotation.text || ''}</textarea>
    `;
    
    const textarea = el.querySelector('textarea');
    textarea.addEventListener('input', (e) => {
      annotation.text = e.target.value;
      this.saveToStorage();
    });
    
    const deleteBtn = el.querySelector('.note-delete');
    deleteBtn.addEventListener('click', () => {
      this.deleteAnnotation(annotation.id);
    });
    
    annotationLayer.appendChild(el);
  }

  deleteAnnotation(id) {
    const index = this.annotations.findIndex(a => a.id === id);
    if (index === -1) return;
    
    this.annotations.splice(index, 1);
    
    const el = document.querySelector(`[data-annotation-id="${id}"]`);
    if (el) el.remove();
    
    this.onAnnotationsChanged?.(this.annotations);
    this.saveToStorage();
  }

  async loadAnnotations() {
    try {
      // FIX: Use chrome.storage.local instead of localStorage (unavailable in MV3 extensions)
      const key = `pdf_annotations_${this.fileName}`;
      const result = await chrome.storage.local.get(key);
      if (result[key]) {
        this.annotations = result[key];
        
        // Re-render all annotations
        for (const annotation of this.annotations) {
          if (annotation.type === 'text') {
            this.renderTextAnnotation(annotation);
          } else {
            this.renderAnnotation(annotation);
          }
        }
        
        this.onAnnotationsChanged?.(this.annotations);
      }
    } catch (error) {
      console.error('Error loading annotations:', error);
    }
  }

  async saveToStorage() {
    try {
      // FIX: Use chrome.storage.local instead of localStorage
      const key = `pdf_annotations_${this.fileName}`;
      await chrome.storage.local.set({ [key]: this.annotations });
    } catch (error) {
      console.error('Error saving annotations:', error);
    }
  }

  exportAnnotations() {
    return JSON.stringify(this.annotations, null, 2);
  }

  importAnnotations(json) {
    try {
      this.annotations = JSON.parse(json);
      
      document.querySelectorAll('.annotation-layer').forEach(layer => {
        layer.innerHTML = '';
      });
      
      for (const annotation of this.annotations) {
        if (annotation.type === 'text') {
          this.renderTextAnnotation(annotation);
        } else {
          this.renderAnnotation(annotation);
        }
      }
      
      this.onAnnotationsChanged?.(this.annotations);
    } catch (error) {
      console.error('Error importing annotations:', error);
    }
  }

  getAnnotations()            { return this.annotations; }
  getAnnotationCount()        { return this.annotations.length; }
  getAnnotationsByPage(p)     { return this.annotations.filter(a => a.page === p); }

  clearAllAnnotations() {
    this.annotations = [];
    document.querySelectorAll('.annotation-layer').forEach(l => { l.innerHTML = ''; });
    this.onAnnotationsChanged?.(this.annotations);
    this.saveToStorage();
  }
}
